import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';
import Sidebar from '../components/common/Sidebar';
import { DatePicker } from '../components/common/DatePicker';

const Section = ({ title, children }) => (
  <div style={{ marginBottom: '2rem' }}>
    <h3 style={{ fontSize: '0.8rem', color: 'var(--accent)', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '1rem', paddingBottom: '0.5rem', borderBottom: '1px solid var(--border)' }}>{title}</h3>
    {children}
  </div>
);

const Field = ({ label, required, children, span = 1 }) => (
  <div className="form-group" style={{ gridColumn: span > 1 ? `span ${span}` : undefined }}>
    <label className="form-label">{label}{required && <span style={{ color: 'var(--accent)', marginLeft: '0.2rem' }}>*</span>}</label>
    {children}
  </div>
);

export default function RequestFormPage() {
  const { id } = useParams();
  const isEdit = Boolean(id);
  const { user } = useAuth();
  const navigate = useNavigate();
  const [categories, setCategories] = useState([]);
  const [sites, setSites] = useState([]);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [files, setFiles] = useState([]);
  const [existingFiles, setExistingFiles] = useState([]);
  const [requestStatus, setRequestStatus] = useState('draft');

  const [form, setForm] = useState({
    title: '', purpose: '', part_description: '', quantity: 1,
    functional_requirement: '', visual_requirement: '', category_id: '',
    criticality: 'normal', use_environment: '',
    dimensions: '', scale: '', tolerance: '', surface_finish: '',
    strength_requirement: '', color_preference: '', material_preference: '',
    infill_percentage: '', layer_height: '', orientation: '',
    priority: 'normal', priority_reason: '', requested_due_date: '',
    project_reference: '', customer_reference: '', site_id: '',
  });

  useEffect(() => {
    api.get('/categories').then(r => setCategories(r.data));
    api.get('/sites').then(r => {
      setSites(r.data);
      if (!isEdit && r.data.length === 1) setForm(f => ({ ...f, site_id: r.data[0].id }));
    });
    if (isEdit) {
      setLoading(true);
      api.get(`/requests/${id}`).then(r => {
        const d = r.data;
        // Store status for conditional UI
        setRequestStatus(d.status || 'draft');
        setForm({
          title: d.title || '', purpose: d.purpose || '',
          part_description: d.part_description || '', quantity: d.quantity || 1,
          functional_requirement: d.functional_requirement || '',
          visual_requirement: d.visual_requirement || '',
          category_id: d.category_id || '', criticality: d.criticality || 'normal',
          use_environment: d.use_environment || '',
          dimensions: d.dimensions || '', scale: d.scale || '',
          tolerance: d.tolerance || '', surface_finish: d.surface_finish || '',
          strength_requirement: d.strength_requirement || '',
          color_preference: d.color_preference || '',
          material_preference: d.material_preference || '',
          infill_percentage: d.infill_percentage || '',
          layer_height: d.layer_height || '', orientation: d.orientation || '',
          priority: d.priority || 'normal', priority_reason: d.priority_reason || '',
          requested_due_date: d.requested_due_date ? d.requested_due_date.split('T')[0] : '',
          project_reference: d.project_reference || '',
          customer_reference: d.customer_reference || '',
          site_id: d.site_id || '',
        });
        setExistingFiles(d.attachments || []);
        setLoading(false);
      });
    }
  }, [id, isEdit]);

  const set = (key, val) => setForm(f => ({ ...f, [key]: val }));

  const handleSubmit = async (action) => {
    if (!form.title.trim()) { setError('Title is required'); return; }
    if (!form.site_id) { setError('Site is required'); return; }
    setSaving(true); setError('');
    try {
      let requestId = id;
      if (isEdit) {
        await api.put(`/requests/${id}`, form);
      } else {
        const res = await api.post('/requests', form);
        requestId = res.data.id;
      }

      // Upload files
      if (files.length > 0) {
        const fd = new FormData();
        files.forEach(f => fd.append('files', f));
        await api.post(`/requests/${requestId}/files`, fd, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
      }

      // Submit/Resubmit
      if (action === 'submit' || action === 'resubmit') {
        const comment = action === 'resubmit'
          ? 'Request updated and resubmitted after information correction'
          : 'Request submitted by requester';
        await api.patch(`/requests/${requestId}/status`, { status: 'submitted', comment });
      }

      navigate(`/requests/${requestId}`);
    } catch (err) {
      setError(err.response?.data?.error || 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  if (loading) return (
    <div className="page"><Sidebar/>
      <div className="main-content" style={{ display:'flex', alignItems:'center', justifyContent:'center' }}>
        <span className="spinner" style={{ width: 32, height: 32 }}/>
      </div>
    </div>
  );

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>
              {isEdit ? 'Edit Request' : 'New 3D Print Request'}
            </h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Fill in the required information about your 3D printing need
            </p>
          </div>
          <button className="btn btn-ghost" onClick={() => navigate(-1)}>Cancel</button>
        </div>

        <div className="page-body" style={{ maxWidth: 900 }}>
          {error && <div className="alert alert-error" style={{ marginBottom: '1.5rem' }}>{error}</div>}

          {/* IDENTIFICATION */}
          <Section title="1. Request Identification">
            <div className="grid-2">
              <Field label="Title" required span={2}>
                <input className="form-input" value={form.title} onChange={e => set('title', e.target.value)} placeholder="Descriptive title of the part or need"/>
              </Field>
              <Field label="Project / Reference">
                <input className="form-input" value={form.project_reference} onChange={e => set('project_reference', e.target.value)} placeholder="Project code or name"/>
              </Field>
              <Field label="Customer Reference">
                <input className="form-input" value={form.customer_reference} onChange={e => set('customer_reference', e.target.value)} placeholder="Customer or order reference"/>
              </Field>
              <Field label="Site" required>
                <select className="form-select" value={form.site_id} onChange={e => set('site_id', e.target.value)}>
                  <option value="">Select site</option>
                  {sites.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </Field>
            </div>
          </Section>

          {/* DESCRIPTION */}
          <Section title="2. Request Description">
            <div className="grid-2">
              <Field label="Purpose" span={2}>
                <textarea className="form-textarea" value={form.purpose} onChange={e => set('purpose', e.target.value)} placeholder="Why is this part needed? What problem does it solve?"/>
              </Field>
              <Field label="Part Description" span={2}>
                <textarea className="form-textarea" value={form.part_description} onChange={e => set('part_description', e.target.value)} placeholder="Describe the part: shape, features, assembly context…"/>
              </Field>
              <Field label="Quantity" required>
                <input type="number" min="1" className="form-input" value={form.quantity} onChange={e => set('quantity', parseInt(e.target.value) || 1)}/>
              </Field>
              <Field label="Category">
                <select className="form-select" value={form.category_id} onChange={e => set('category_id', e.target.value)}>
                  <option value="">Select category</option>
                  {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </Field>
              <Field label="Criticality">
                <select className="form-select" value={form.criticality} onChange={e => set('criticality', e.target.value)}>
                  <option value="low">Low — Cosmetic / non-functional</option>
                  <option value="normal">Normal — Standard functional part</option>
                  <option value="high">High — Production-critical</option>
                  <option value="urgent">Urgent — Line stoppage risk</option>
                </select>
              </Field>
              <Field label="Expected Use Environment">
                <input className="form-input" value={form.use_environment} onChange={e => set('use_environment', e.target.value)} placeholder="e.g. Indoor, UV exposure, high temperature…"/>
              </Field>
              <Field label="Functional Requirements" span={2}>
                <textarea className="form-textarea" value={form.functional_requirement} onChange={e => set('functional_requirement', e.target.value)} placeholder="Load, stress, snap-fit, heat resistance, chemical exposure…"/>
              </Field>
              <Field label="Visual / Aesthetic Requirements" span={2}>
                <textarea className="form-textarea" value={form.visual_requirement} onChange={e => set('visual_requirement', e.target.value)} placeholder="Appearance, surface quality, color matching…" style={{ minHeight: 60 }}/>
              </Field>
            </div>
          </Section>

          {/* TECHNICAL */}
          <Section title="3. Technical Data">
            <div className="grid-2">
              <Field label="Dimensions or Scale">
                <input className="form-input" value={form.dimensions} onChange={e => set('dimensions', e.target.value)} placeholder="e.g. 120mm × 80mm × 40mm"/>
              </Field>
              <Field label="Scale / Scaling Factor">
                <input className="form-input" value={form.scale} onChange={e => set('scale', e.target.value)} placeholder="e.g. 1:1, 1:2, or 150%"/>
              </Field>
              <Field label="Tolerance Requirements">
                <input className="form-input" value={form.tolerance} onChange={e => set('tolerance', e.target.value)} placeholder="e.g. ±0.2mm, tight fit, press fit…"/>
              </Field>
              <Field label="Surface Finish">
                <input className="form-input" value={form.surface_finish} onChange={e => set('surface_finish', e.target.value)} placeholder="e.g. As-printed, sanded, painted…"/>
              </Field>
              <Field label="Strength Requirement">
                <input className="form-input" value={form.strength_requirement} onChange={e => set('strength_requirement', e.target.value)} placeholder="e.g. Structural, light-duty, display only…"/>
              </Field>
              <Field label="Color Preference">
                <input className="form-input" value={form.color_preference} onChange={e => set('color_preference', e.target.value)} placeholder="e.g. Black, RAL 7016, match drawing…"/>
              </Field>
              <Field label="Material Preference">
                <input className="form-input" value={form.material_preference} onChange={e => set('material_preference', e.target.value)} placeholder="e.g. PLA, PETG, ABS, flexible…"/>
              </Field>
              <Field label="Infill % (if known)">
                <input type="number" min="0" max="100" className="form-input" value={form.infill_percentage} onChange={e => set('infill_percentage', e.target.value)} placeholder="e.g. 20"/>
              </Field>
              <Field label="Layer Height (mm)">
                <input type="number" step="0.05" min="0.05" max="0.4" className="form-input" value={form.layer_height} onChange={e => set('layer_height', e.target.value)} placeholder="e.g. 0.2"/>
              </Field>
              <Field label="Preferred Orientation">
                <input className="form-input" value={form.orientation} onChange={e => set('orientation', e.target.value)} placeholder="e.g. Flat on bed, upright, angled…"/>
              </Field>
            </div>
          </Section>

          {/* PLANNING */}
          <Section title="4. Planning & Priority">
            <div className="grid-2">
              <Field label="Priority" required>
                <select className="form-select" value={form.priority} onChange={e => set('priority', e.target.value)}>
                  <option value="low">Low</option>
                  <option value="normal">Normal</option>
                  <option value="high">High</option>
                  <option value="critical">Critical</option>
                </select>
              </Field>
              <Field label="Requested Due Date">
                <DatePicker value={form.requested_due_date} onChange={v => set('requested_due_date', v)} placeholder="Select due date"/>
              </Field>
              <Field label="Reason for Priority / Urgency" span={2}>
                <textarea className="form-textarea" value={form.priority_reason} onChange={e => set('priority_reason', e.target.value)} placeholder="If high or critical, explain why…" style={{ minHeight: 60 }}/>
              </Field>
            </div>
          </Section>

          {/* FILES */}
          <Section title="5. File Attachments">
            <div style={{ marginBottom: '1rem' }}>
              <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '0.75rem' }}>
                Supported: STL, STEP, OBJ, 3MF, DWG, DXF, PDF, PNG, JPG (max 50MB each)
              </p>
              <input
                type="file" multiple
                accept=".stl,.step,.stp,.obj,.3mf,.cad,.pdf,.png,.jpg,.jpeg,.dwg,.dxf,.zip"
                onChange={e => {
                  const newFiles = Array.from(e.target.files);
                  setFiles(prev => {
                    // Deduplicate by name+size
                    const existing = new Set(prev.map(f => f.name + f.size));
                    const added = newFiles.filter(f => !existing.has(f.name + f.size));
                    return [...prev, ...added];
                  });
                  // Reset input so same file can be re-added if removed
                  e.target.value = '';
                }}
                style={{ display: 'none' }}
                id="file-input"
              />
              <label htmlFor="file-input" className="btn btn-secondary" style={{ cursor: 'pointer' }}>
                <svg width="14" height="14" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                  <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"/>
                </svg>
                Choose files
              </label>
              {files.length > 0 && (
                <div style={{ marginTop: '0.75rem', display: 'flex', flexDirection: 'column', gap: '0.35rem' }}>
                  <p style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginBottom: '0.25rem' }}>
                    {files.length} file{files.length !== 1 ? 's' : ''} selected
                  </p>
                  {files.map((f, i) => (
                    <div key={i} style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.35rem 0.6rem', background: 'var(--bg-hover)', borderRadius: 6 }}>
                      <span style={{ color: 'var(--green)' }}>✓</span>
                      <span style={{ flex: 1 }}>{f.name}</span>
                      <span style={{ color: 'var(--text-muted)', fontSize: '0.72rem' }}>({(f.size / 1024 / 1024).toFixed(1)} MB)</span>
                      <button
                        type="button"
                        onClick={() => setFiles(prev => prev.filter((_, idx) => idx !== i))}
                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--red)', fontSize: 16, lineHeight: 1, padding: '0 2px' }}
                        title="Remove file"
                      >×</button>
                    </div>
                  ))}
                </div>
              )}
            </div>
            {existingFiles.length > 0 && (
              <div>
                <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: '0.5rem', textTransform: 'uppercase', letterSpacing: '0.05em' }}>Existing files</p>
                {existingFiles.map(f => (
                  <div key={f.id} style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.3rem' }}>
                    <span style={{ color: 'var(--blue)' }}>📎</span> {f.original_name}
                  </div>
                ))}
              </div>
            )}
          </Section>

          {/* Actions */}
          {/* Info banner when editing after info request */}
          {isEdit && requestStatus === 'more_info_required' && (
            <div className="alert alert-warning" style={{ marginBottom: '1rem' }}>
              <strong>⚠ Information Required</strong> — The coordinator has requested corrections.
              Update the necessary fields and click <strong>Save &amp; Resubmit</strong>.
            </div>
          )}

          <div style={{ display: 'flex', gap: '0.75rem', justifyContent: 'flex-end', paddingTop: '1rem', borderTop: '1px solid var(--border)' }}>
            <button className="btn btn-ghost" onClick={() => navigate(-1)} disabled={saving}>Cancel</button>
            {requestStatus !== 'more_info_required' && (
              <button className="btn btn-secondary" onClick={() => handleSubmit('save')} disabled={saving}>
                {saving ? <span className="spinner" style={{ width: 14, height: 14 }}/> : null}
                Save as Draft
              </button>
            )}
            {requestStatus === 'more_info_required' ? (
              <button className="btn btn-primary" onClick={() => handleSubmit('resubmit')} disabled={saving}
                style={{ background: 'var(--yellow)', color: '#000' }}>
                {saving ? <span className="spinner" style={{ width: 14, height: 14 }}/> : null}
                💾 Save &amp; Resubmit
              </button>
            ) : (
              <button className="btn btn-primary" onClick={() => handleSubmit('submit')} disabled={saving}>
                {saving ? <span className="spinner" style={{ width: 14, height: 14 }}/> : null}
                Save &amp; Submit
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
